@Override
public boolean checkPassword(String rawPassword, String storedPassword) {
    if (rawPassword == null && storedPassword == null)
        return true;
    if (rawPassword == null || storedPassword == null)
        return false;
    return rawPassword.equals(storedPassword);
}

@Override
public void registerUser(User user) {
